## Implementation Guide

1. Import the Firecat schema and `MessageData` type.

2. Implement the function:
   ```typescript
   import firecatSchema from "./mod.ts";
   import type { MessageData } from "@bandeira-tech/b3nd-sdk";
   import type { NodeProtocolInterface } from "@bandeira-tech/b3nd-sdk/types";

   export async function replayValidation(
     client: NodeProtocolInterface,
     envelopeUri: string,
   ): Promise<{ verdict: "valid" } | { verdict: "invalid"; reason: string }> {
     const envelope = await client.read(envelopeUri);
     if (!envelope.success || !envelope.record) {
       return { verdict: "invalid", reason: "Envelope not found" };
     }

     const msg = envelope.record.data as MessageData;
     if (!msg?.payload?.outputs || !Array.isArray(msg.payload.outputs)) {
       return { verdict: "invalid", reason: "Invalid envelope format" };
     }

     const readFn = <T>(uri: string) => client.read<T>(uri);

     for (const [outputUri, outputValue] of msg.payload.outputs) {
       const url = URL.parse(outputUri);
       if (!url) {
         return { verdict: "invalid", reason: `Invalid output URI: ${outputUri}` };
       }

       const program = `${url.protocol}//${url.hostname}`;
       const validator = firecatSchema[program];
       if (!validator) {
         return { verdict: "invalid", reason: `Unknown program: ${program}` };
       }

       // Run validator -- note: write-once checks may fail for already-written outputs
       // We pass message context for envelope-level checks (conservation, auth)
       const result = await validator({
         uri: outputUri,
         value: outputValue,
         read: readFn,
         message: msg,
       });

       if (!result.valid) {
         // Distinguish "already exists" (expected for replayed outputs) from real failures
         if (result.error?.includes("immutable") || result.error?.includes("already")) {
           continue; // Expected for outputs written during pending processing
         }
         return { verdict: "invalid", reason: result.error ?? "Validation failed" };
       }
     }

     return { verdict: "valid" };
   }
   ```

3. Write tests that construct valid and invalid envelopes and verify replay results.

